insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-ore-dress', '오르 드레스룸', '바람에 자연스럽게 움직이는 실루엣을 제안해요. 햇살 아래에서도 맑게 남는 피부 표현을 우선해요.', array['쉬폰', '야외 촬영', '물광']::text[], '드레스는 종류와 사이즈별로 약 600벌을 보유하고, 턱시도는 95·100·105 사이즈를 기본으로 준비해요.', 0);
