insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-sodam-dress', '소담 브라이덜', '제주의 담백한 풍경과 어울리는 단정한 드레스를 골라요. 피부의 결을 살리고 사진에서 또렷한 포인트를 더해요.', array['새틴', '클래식', '세미 매트']::text[], '야외 촬영용 드레스와 신랑 예복, 온결 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 1);
