insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-midnight-dress', '미드나잇 드레스', '노을부터 밤까지 색감이 또렷한 드레스를 준비합니다. 클래식한 드레스와 균형을 이루는 섬세한 메이크업이에요.', array['실크', '이브닝', '세미 매트']::text[], '야외 촬영용 드레스와 신랑 예복, 부드러운 결의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 2);
