insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-shore-dress', '쇼어 브라이덜', '해안 바람에도 가볍게 움직이는 드레스를 준비해요. 사진 속 눈매와 윤곽의 균형을 차분하게 잡아드립니다.', array['슬립 드레스', '바다', '정교한 음영']::text[], '야외 촬영용 드레스와 신랑 예복, 프레임 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 4);
