insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-bloom-dress', '블룸 드레스', '밝은 야외 촬영에 어울리는 산뜻한 드레스 구성이에요. 꾸민 듯 안 꾸민 듯한 내추럴 웨딩 메이크업을 완성해요.', array['튤', '밝은 톤', '누드 메이크업']::text[], '야외 촬영용 드레스와 신랑 예복, 누드 노트의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 6);
