insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-meadow-bridal', '메도우 브라이덜', '목장과 초원에서 자연스러운 선이 살아나는 드레스를 골라요. 차분한 색조와 고급스러운 결을 오래 유지합니다.', array['쉬폰', '목장', '뮤트 톤']::text[], '야외 촬영용 드레스와 신랑 예복, 허쉬 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 7);
