insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-dear-dress', '디어 드레스', '작고 섬세한 디테일이 사진에 남는 웨딩룩을 만들어요. 피부 본연의 톤을 해치지 않는 섬세한 보정을 추구해요.', array['비즈', '베일', '피부 표현']::text[], '야외 촬영용 드레스와 신랑 예복, 캄 스트로크의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 9);
