insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-muse-bridal', '뮤즈 브라이덜', '나만의 한 벌을 찾는 커플을 위한 균형 잡힌 피팅이에요. 필름 사진에 어울리는 부드러운 색조를 제안해요.', array['세미 A라인', '피팅 3벌', '필름 무드']::text[], '야외 촬영용 드레스와 신랑 예복, 멜로우 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 11);
