insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-river-dress', '리버 드레스', '흐르는 선이 예쁜 드레스로 움직임 있는 촬영을 돕습니다. 빛이 강한 시간에도 맑고 또렷한 인상을 남겨요.', array['드레이프', '플루이드', '광채 피부']::text[], '야외 촬영용 드레스와 신랑 예복, 루멘 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 14);
