insert into public.styling_products (shop_id, id, kind, name, description, regular_price, partner_price, included_services, add_ons, notice, sort_order) values ('shop-house-of-veil', 'single-tuxedo-15', 'single', '턱시도 대여', '신랑 예복 상·하의 한 벌을 준비해요.', '{"total":110000,"vatAmount":0,"taxIncluded":false}'::jsonb, null, array['턱시도 상·하의 세트', '95·100·105 사이즈 피팅']::text[], '[{"id":"shirt-15","name":"셔츠 대여","price":10000,"description":"턱시도와 어울리는 기본 셔츠를 함께 대여해요."}]'::jsonb, '110 사이즈는 일부 기본 색상으로 상담 후 준비할 수 있어요.', 5);
