insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-pearl-closet', '펄 클로젯', '은은한 포인트가 있는 드레스를 차분하게 추천합니다. 초여름 제주의 싱그러움을 살리는 가벼운 표현이에요.', array['펄', '세미 매트', '프레시']::text[], '야외 촬영용 드레스와 신랑 예복, 준 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 16);
