insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-reveal-dress', '리빌 드레스', '두 벌의 분위기를 확실히 다르게 가져가고 싶은 커플에게 맞아요. 노을과 야간 촬영까지 색감이 무너지지 않게 준비해요.', array['투피스', '변형', '노을']::text[], '야외 촬영용 드레스와 신랑 예복, 씬온의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 17);
