insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-studio-lily', '스튜디오 릴리', '사랑스러운 질감과 밝은 색감을 살리는 드레스를 준비해요. 깨끗한 캔버스처럼 정돈된 피부 표현을 우선합니다.', array['레이스', '러블리', '깨끗한 피부']::text[], '야외 촬영용 드레스와 신랑 예복, 페이퍼 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 18);
