insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-petal-room', '페탈 룸', '봄과 초여름 제주에 어울리는 가벼운 소재를 제안해요. 은은하게 빛나는 새틴 피부 표현과 헤어를 제안해요.', array['페탈 소매', '봄', '새틴 광']::text[], '야외 촬영용 드레스와 신랑 예복, 새틴 메이크업의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 21);
