insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-seafoam-dress', '씨폼 드레스', '바다의 밝은 반사광에도 깨끗하게 남는 실루엣을 골라요. 해가 진 뒤에도 입체감이 남는 메이크업을 완성해요.', array['해안', '화이트', '야간']::text[], '야외 촬영용 드레스와 신랑 예복, 애프터글로우의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 23);
