insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-noble-dress', '노블 드레스', '단정하고 격식 있는 분위기를 원하는 커플에게 어울려요. 잔머리와 작은 디테일이 예쁜 사랑스러운 헤어를 만들어요.', array['롱슬리브', '포멀', '잔머리']::text[], '야외 촬영용 드레스와 신랑 예복, 쁘띠 헤어의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 25);
