insert into public.styling_products (shop_id, id, kind, name, description, regular_price, partner_price, included_services, add_ons, notice, sort_order) values ('shop-noble-dress', 'single-dress-25', 'single', '드레스 대여', '드레스 한 벌을 취향과 촬영 씬에 맞춰 골라요.', '{"total":150000,"maximumTotal":400000,"vatAmount":0,"taxIncluded":false}'::jsonb, null, array['드레스 1벌', '기본 피팅', '사이즈 상담']::text[], '[{"id":"hanbok-25","name":"신랑·신부 한복 세트","price":330000,"description":"두 분 한복과 기본 소품을 함께 준비해요."}]'::jsonb, '드레스 디자인과 등급에 따라 금액이 달라지고 VAT는 별도예요.', 4);
