insert into public.styling_products (shop_id, id, kind, name, description, regular_price, partner_price, included_services, add_ons, notice, sort_order) values ('shop-veiling-day', 'single-dress-27', 'single', '드레스 대여', '드레스 한 벌을 취향과 촬영 씬에 맞춰 골라요.', '{"total":150000,"maximumTotal":400000,"vatAmount":0,"taxIncluded":false}'::jsonb, null, array['드레스 1벌', '기본 피팅', '사이즈 상담']::text[], '[{"id":"hanbok-27","name":"신랑·신부 한복 세트","price":330000,"description":"두 분 한복과 기본 소품을 함께 준비해요."}]'::jsonb, '드레스 디자인과 등급에 따라 금액이 달라지고 VAT는 별도예요.', 4);
insert into public.styling_products (shop_id, id, kind, name, description, regular_price, partner_price, included_services, add_ons, notice, sort_order) values ('shop-veiling-day', 'single-tuxedo-27', 'single', '턱시도 대여', '신랑 예복 상·하의 한 벌을 준비해요.', '{"total":110000,"vatAmount":0,"taxIncluded":false}'::jsonb, null, array['턱시도 상·하의 세트', '95·100·105 사이즈 피팅']::text[], '[{"id":"shirt-27","name":"셔츠 대여","price":10000,"description":"턱시도와 어울리는 기본 셔츠를 함께 대여해요."}]'::jsonb, '110 사이즈는 일부 기본 색상으로 상담 후 준비할 수 있어요.', 5);
