insert into public.styling_shops (id, name, introduction, keywords, inventory_description, sort_order) values ('shop-dawn-dress', '던 드레스', '이른 아침 촬영에도 맑게 보이는 가벼운 질감이 특징이에요. 노을빛 아래 깊이가 생기는 로맨틱한 색조를 제안합니다.', array['아침 촬영', '오간자', '로맨틱']::text[], '야외 촬영용 드레스와 신랑 예복, 폴링 라이트의 헤어·메이크업을 한곳에서 준비할 수 있어요.', 28);
